const crypto = require('crypto');

// Secreto (L-C-10): $vars.__PEGAR_SECRETO_O_USAR_VARIABLE__ si existe; si no, placeholder pegado a mano (Modo B).
// Assert duro POR PREFIJO sobrevive al find-replace del placeholder.
const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.__PEGAR_SECRETO_O_USAR_VARIABLE__)
  ? $vars.__PEGAR_SECRETO_O_USAR_VARIABLE__
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('__PEGAR_SECRETO_O_USAR_VARIABLE__ no configurado; abortando (assert duro por prefijo).');
}

const EXPECTED_ACTION = 'cobranza.registrar_cobro';
const ROLES_OK = ['vicky', 'socio'];
const ENUM_ACTOR = ['vicky', 'franco', 'rodrigo', 'remo'];
const ENUM_SUBTIPO = ['bancaria', 'mp'];
const MONTO_MAX = 9999999999.99;
const ORIGEN_MAX = 120;
const DESC_MAX = 200;
const TS_WINDOW_MS = 300000;
const MAXLEN = 1000;
const ENVELOPE_KEYS = ['action', 'payload', 'rol', 'ambiente_esperado', 'ts', 'nonce', 'actor'];
const PAYLOAD_KEYS = ['id_reserva', 'monto_efectivo', 'monto_transferencia', 'subtipo_transferencia',
  'monto_otros', 'origen_otros', 'descripcion_otros', 'idempotency_key', 'notas'];

function actorCoherente(rol, nombre) {
  if (rol === 'vicky') return nombre === 'vicky';
  if (rol === 'socio') return nombre === 'franco' || nombre === 'rodrigo' || nombre === 'remo';
  return false;
}
const fail = (error, message) => [{ json: { __auth_ok: false, error: error, message: message } }];

// Raw body como Buffer EXACTO (PATRON A12; L-C-05). Webhook typeVersion 2.1.
const item = $input.first();
const wh = item.json;

let raw = null;
let via = 'none';
const diag = { rawread: 'v5' };
try {
  if (item.binary && item.binary.data) {
    raw = await this.helpers.getBinaryDataBuffer(0, 'data');
    if (raw && raw.length) via = 'getBinaryDataBuffer';
  }
} catch (e) { diag.getBinErr = String((e && e.message) || e); raw = null; }
if (!raw || !raw.length) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) { raw = rawField; via = 'rawBody.buffer'; }
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) { raw = Buffer.from(rawField.data); via = 'rawBody.serialized'; }
  else if (typeof rawField === 'string') { raw = Buffer.from(rawField, 'utf8'); via = 'rawBody.string'; }
}
if (!raw || raw.length === 0) {
  diag.via = via;
  diag.binary = !!(item && item.binary);
  const bd = (item && item.binary && item.binary.data) ? item.binary.data : null;
  diag.binaryDataKeys = bd ? Object.keys(bd) : [];
  diag.rawBodyType = typeof wh.rawBody;
  return fail('raw_body_ausente', 'raw body ausente | diag ' + JSON.stringify(diag));
}

// Firma HMAC-SHA256 timing-safe (patron A12).
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(raw).digest('hex');
let firmaOk = false;
try {
  const a = Buffer.from(String(sigHeader || ''));
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) { firmaOk = false; }
if (!firmaOk) return fail('firma_invalida', 'firma invalida');

let env;
try { env = JSON.parse(raw.toString('utf8')); } catch (e) { return fail('payload_invalido', 'sobre no es JSON'); }
if (typeof env !== 'object' || env === null || Array.isArray(env)) return fail('payload_invalido', 'sobre invalido');
for (const k of Object.keys(env)) if (!ENVELOPE_KEYS.includes(k)) return fail('payload_invalido', 'clave de sobre no permitida: ' + k);

if (typeof env.ts !== 'number' || !Number.isFinite(env.ts)) return fail('payload_invalido', 'ts invalido');
if (Math.abs(Date.now() - env.ts) > TS_WINDOW_MS) return fail('ts_fuera_de_ventana', 'ts fuera de ventana');
if (env.action !== EXPECTED_ACTION) return fail('payload_invalido', 'action no coincide con el endpoint');
if (!ROLES_OK.includes(env.rol)) return fail('rol_no_permitido', 'rol no habilitado');
if (typeof env.actor !== 'string' || !ENUM_ACTOR.includes(env.actor)) return fail('payload_invalido', 'actor invalido');
if (!actorCoherente(env.rol, env.actor)) return fail('rol_no_permitido', 'actor incoherente con rol');
if (typeof env.ambiente_esperado !== 'string' || env.ambiente_esperado.length === 0) return fail('payload_invalido', 'ambiente_esperado invalido');
if (typeof env.nonce !== 'string' || env.nonce.length === 0) return fail('payload_invalido', 'nonce invalido');

// ---- Revalidacion del payload multi-porcion (2da defensa, ESPEJO de payloadRegistrarCobro) ----
const p = env.payload;
if (typeof p !== 'object' || p === null || Array.isArray(p)) return fail('payload_invalido', 'payload invalido');
for (const k of Object.keys(p)) if (!PAYLOAD_KEYS.includes(k)) return fail('payload_invalido', 'clave de payload no permitida: ' + k);

if (typeof p.id_reserva !== 'number' || !Number.isSafeInteger(p.id_reserva) || p.id_reserva <= 0) return fail('payload_invalido', 'id_reserva debe ser entero positivo');

function montoPorcion(v, nombre) {
  if (v === undefined || v === null) return { ok: true, val: 0 };
  if (typeof v !== 'number' || !Number.isFinite(v) || v < 0) return { ok: false, message: nombre + ' debe ser numero >= 0 finito' };
  const cents = Math.round(v * 100);
  if (Math.abs(v * 100 - cents) > 1e-6) return { ok: false, message: nombre + ' admite maximo 2 decimales' };
  if (v > MONTO_MAX) return { ok: false, message: nombre + ' fuera de rango' };
  return { ok: true, val: v };
}
const ef = montoPorcion(p.monto_efectivo, 'monto_efectivo'); if (!ef.ok) return fail('payload_invalido', ef.message);
const tr = montoPorcion(p.monto_transferencia, 'monto_transferencia'); if (!tr.ok) return fail('payload_invalido', tr.message);
const ot = montoPorcion(p.monto_otros, 'monto_otros'); if (!ot.ok) return fail('payload_invalido', ot.message);

const suma = ef.val + tr.val + ot.val;
if (!(suma > 0)) return fail('payload_invalido', 'al menos una porcion de saldo debe ser mayor a cero');

let subtipo = 'bancaria';
if (p.subtipo_transferencia !== undefined && p.subtipo_transferencia !== null) {
  if (typeof p.subtipo_transferencia !== 'string' || !ENUM_SUBTIPO.includes(p.subtipo_transferencia)) return fail('payload_invalido', 'subtipo_transferencia invalido (bancaria|mp)');
  subtipo = p.subtipo_transferencia;
}

let origen = null;
let descripcion = null;
if (ot.val > 0) {
  if (typeof p.origen_otros !== 'string' || p.origen_otros.trim() === '' || p.origen_otros.length > ORIGEN_MAX) return fail('payload_invalido', 'origen_otros requerido (1..120) cuando monto_otros > 0');
  if (typeof p.descripcion_otros !== 'string' || p.descripcion_otros.trim() === '' || p.descripcion_otros.length > DESC_MAX) return fail('payload_invalido', 'descripcion_otros requerido (1..200) cuando monto_otros > 0');
  origen = p.origen_otros.trim();
  descripcion = p.descripcion_otros.trim();
} else if ((p.origen_otros !== undefined && p.origen_otros !== null) || (p.descripcion_otros !== undefined && p.descripcion_otros !== null)) {
  return fail('payload_invalido', 'origen_otros/descripcion_otros no permitidos cuando monto_otros es 0');
}

const key = p.idempotency_key;
if (typeof key !== 'string' || key.length < 8 || key.length > 64 || !/^[A-Za-z0-9_-]+$/.test(key)) return fail('payload_invalido', 'idempotency_key invalida');

if (p.notas !== undefined && p.notas !== null && (typeof p.notas !== 'string' || p.notas.length > MAXLEN)) return fail('payload_invalido', 'notas invalida');

return [{ json: {
  __auth_ok: true,
  action: env.action, rol: env.rol, actor: env.actor,
  ambiente_esperado: env.ambiente_esperado, ts: env.ts, nonce: env.nonce,
  payload: {
    id_reserva: p.id_reserva,
    monto_efectivo: ef.val,
    monto_transferencia: tr.val,
    subtipo_transferencia: subtipo,
    monto_otros: ot.val,
    origen_otros: origen,
    descripcion_otros: descripcion,
    idempotency_key: key,
    notas: (p.notas != null ? p.notas : null)
  }
}}];

// Combina el resultado de validar_firma_ts_rol con el ambiente leido de la BD.
const v = $('validar_firma_ts_rol').first().json;
if (!v.__auth_ok) {
  return [{ json: { acceso: false, error: v.error, message: v.message } }];
}
const ambRow = $('leer_ambiente').first().json;
const dbAmbiente = ambRow.ambiente;
if (dbAmbiente !== v.ambiente_esperado) {
  return [{ json: { acceso: false, error: 'ambiente_incorrecto', message: 'ambiente no coincide' } }];
}
if (dbAmbiente !== 'test') {
  return [{ json: { acceso: false, error: 'ambiente_incorrecto', message: 'wrapper TEST-only' } }];
}
return [{ json: { acceso: true, rol: v.rol, actor: v.actor, payload: v.payload, ambiente: dbAmbiente } }];

// A10-MP -- Derivacion server-side: source_event determinista (PII-free) + lineas[] payload-ready
// para registrar_pago (consolida N3+N4.5 de W09: porciones, recargo 5%, otros como efectivo-equiv ARS
// con traza, orden efectivo->otros->transferencia(saldo)->extra). NO registra: el alta ocurre en PG_cobro_mp.
const crypto = require('crypto');
const va = $('verificar_acceso').first().json;
const p = va.payload;
const actor = va.actor;

const ef = Number(p.monto_efectivo || 0);
const tr = Number(p.monto_transferencia || 0);
const ot = Number(p.monto_otros || 0);

// Recargo 5% SOLO sobre la porcion de transferencia (interno, no lo carga el operador).
const recargo = tr > 0 ? Math.round(tr * 0.05) : 0;
const suma_saldo = ef + tr + ot;

// Punto #5: 'mp' (gateway normalizado) -> 'transferencia_mp'; cualquier otro -> 'transferencia_bancaria'.
const MEDIO_TRANSFERENCIA = (p.subtipo_transferencia === 'mp') ? 'transferencia_mp' : 'transferencia_bancaria';

// source_event UNICO y determinista del evento (mismo para TODAS las lineas). Patron W10.
const canon = String(p.id_reserva) + '|' + p.idempotency_key;
const hash = crypto.createHash('sha256').update(canon, 'utf8').digest('hex').slice(0, 12);
const source_event = 'portal_test_a10mp_res' + p.id_reserva + '_' + hash;

// Traza de "otros" (medio_original + registrado_como); origen/descripcion ya validados/trim por el preambulo.
const nota_otros = ot > 0
  ? ('medio_original=otros; origen_otros=' + p.origen_otros + '; descripcion_otros=' + p.descripcion_otros + '; registrado_como=efectivo_ars')
  : '';

// Cada linea ES un payload completo para registrar_pago (shape de N4.5).
function linea(tipo, medio_pago, monto, notas_linea) {
  return {
    id_reserva: p.id_reserva,
    tipo: tipo,
    medio_pago: medio_pago,
    monto_esperado: monto,
    monto_recibido: monto,        // capa fuerza recibido = esperado
    moneda: 'ARS',
    estado_inicial: 'confirmado', // capa fuerza confirmado
    validado_por: actor,
    notas: notas_linea,
    source_event: source_event
  };
}

// B3.2 -- Nota del operador (campo opcional `notas` del payload). Se ANEXA a las notas internas de las
// lineas saldo SIN pisar la traza interna (porcion_efectivo / porcion_transferencia / traza de otros).
// NO se aplica a la linea `extra` (auto-generada, conserva 'recargo_5_saldo_transferencia').
// Forma parte de la firma canonica (vive en notas): misma key + nota distinta -> conflicto (correcto).
function appendNotaOperador(base) {
  const n = (p.notas != null) ? String(p.notas).trim() : '';
  return (n === '') ? base : (base + '; nota_operador=' + n);
}

const lineas = [];
if (ef > 0) lineas.push(linea('saldo', 'efectivo', ef, appendNotaOperador('porcion_efectivo')));
if (ot > 0) lineas.push(linea('saldo', 'efectivo', ot, appendNotaOperador(nota_otros)));   // otros -> efectivo-equivalente ARS
if (tr > 0) {
  lineas.push(linea('saldo', MEDIO_TRANSFERENCIA, tr, appendNotaOperador('porcion_transferencia')));
  // Linea extra SOLO si recargo>0: registrar_pago exige monto_esperado>0 (chk_pagos_monto_esperado);
  // una transferencia tan chica que redondea recargo a 0 no genera extra (y no rompe el cobro).
  // El extra NO lleva nota_operador (es interno/automatico).
  if (recargo > 0) lineas.push(linea('extra', MEDIO_TRANSFERENCIA, recargo, 'recargo_5_saldo_transferencia'));
}

// sql_payload = $1 de PG_cobro_mp (y de PG_verif_post). Lleva lineas[] + firma del evento.
const sql_payload = {
  id_reserva: p.id_reserva,
  source_event: source_event,
  validado_por: actor,
  suma_saldo: suma_saldo,
  recargo: recargo,
  cant_lineas: lineas.length,
  lineas: lineas
};

// detalle: echo para el render (no autoridad de montos; los autoritativos salen de PG_verif_post).
const detalle = {
  efectivo: ef,
  transferencia: tr,
  subtipo_transferencia: (tr > 0 ? p.subtipo_transferencia : null),
  otros: ot,
  recargo: recargo
};

return [{ json: { sql_payload: sql_payload, source_event: source_event, id_reserva: p.id_reserva, actor: actor, detalle: detalle } }];

// A10-MP -- RENDER (camino exito). Lee resultado de PG_cobro_mp + verif de PG_verif_post + detalle de derivar.
// Mapea etiquetas internas -> codigos EXTERNOS de la allowlist del gateway (D-C-18).
function pick(nodeName) {
  const items = $(nodeName).all();
  for (const it of items) { if (it.json && it.json.resultado !== undefined) {
    let r = it.json.resultado;
    if (typeof r === 'string') { try { r = JSON.parse(r); } catch (e) {} }
    return r;
  }}
  return null;
}
const out = (env) => [{ json: env }];
const resultado = pick('PG_cobro_mp');
const verif = pick('PG_verif_post');
const der = $('derivar').first().json;

// Sin resultado en la salida principal (no deberia pasar: el write rutea errores a render_error_pg).
if (!resultado) {
  return out({ ok: false, error: { code: 'estado_incierto', message: 'no se pudo determinar el resultado; verifica la reserva antes de reintentar' } });
}

// resultado.ok===true es confirmacion AUTORITATIVA: en alta nueva, abortar_si_falla (D-9B-19) garantiza
// que todas las lineas quedaron confirmadas o habria tirado P0001 (ruteado a render_error_pg). En
// idempotent_match, las lineas previas ya existen. verif aporta los montos post-commit (por source_event).
if (resultado.ok === true) {
  const suma_saldo = verif ? Number(verif.suma_saldo) : null;
  const suma_extra = verif ? Number(verif.suma_extra) : null;
  const saldo_real_actual = verif ? Number(verif.saldo_real_actual) : null;
  const saldo_anterior = (saldo_real_actual !== null && suma_saldo !== null) ? (saldo_real_actual + suma_saldo) : null;
  const total_cobrado = (suma_saldo !== null && suma_extra !== null) ? (suma_saldo + suma_extra) : null;
  const data = {
    source_event: der.source_event,
    cant_lineas: verif ? verif.cant_lineas : der.sql_payload.cant_lineas,
    suma_saldo: suma_saldo,
    suma_extra: suma_extra,
    total_cobrado: total_cobrado,
    saldo_anterior: saldo_anterior,
    saldo_real_actual: saldo_real_actual,
    saldada: (saldo_real_actual === 0),
    idempotent_match: resultado.idempotent_match === true,
    detalle: der.detalle
  };
  return out({ ok: true, data: data });
}

const motivo = resultado.error;
const estadoRes = (resultado.estado_reserva) ? (' (estado: ' + resultado.estado_reserva + ')') : '';
const MAP = {
  reserva_no_existe:    { code: 'no_encontrado', message: 'reserva inexistente' },
  estado_no_cobrable:   { code: 'conflicto',     message: 'la reserva no admite cobranza de saldo' + estadoRes },
  saldo_ya_cancelado:   { code: 'conflicto',     message: 'la reserva ya no tiene saldo pendiente' },
  excede_saldo:         { code: 'conflicto',     message: 'la suma aplicada a saldo excede el saldo pendiente' },
  idempotency_mismatch: { code: 'conflicto',     message: 'idempotency_key reutilizada con datos distintos' }
};
const ext = MAP[motivo] || { code: 'error_interno', message: 'error interno' };
return out({ ok: false, error: ext });

// RENDER de rechazo de acceso (rama IF-false). Los codigos vienen de validar_firma /
// verificar_acceso y ya pertenecen a la allowlist; defensivo: si no, error_interno.
const ALLOW = new Set(['payload_invalido','no_autorizado','rol_no_permitido','accion_desconocida','no_encontrado','conflicto','error_entorno','error_interno','estado_incierto','firma_invalida','ts_fuera_de_ventana','raw_body_ausente','ambiente_incorrecto']);
const va = $('verificar_acceso').first().json;
const code = ALLOW.has(va.error) ? va.error : 'error_interno';
const message = ALLOW.has(va.error) ? (va.message || 'error') : 'error interno';
return [{ json: { ok: false, error: { code: code, message: message } } }];

// RENDER de error del nodo PG_cobranza (P0001 abortar_si_falla o error crudo).
// La transaccion se revirtio: NADA persistio. Externo: error_interno (allowlist; el gateway
// impone el mensaje fijo). Un retry con la MISMA idempotency_key es seguro (idempotente).
return [{ json: { ok: false, error: { code: 'error_interno', message: 'error interno' } } }];
